<script setup lang="ts">
const supabase=useSupabaseClient<any>(),state=ref<any>(null),busy=ref(''),message=ref('')
const policy=reactive({rebate_mode:'usage_rebate',non_material_mode:'auto_canary',material_mode:'off',materiality_threshold:50,max_canary_percent:5,share_verified_improvements:true})
const improvement=reactive({project_id:'',title:'',objective:'',customer_facing:false,data_or_permissions:false,hard_to_reverse:false,affected_users:0,revenue_at_risk_cents:0})
const contribution=reactive({title:'',problem_class:'',pattern_summary:'',metric:'',improvement_percent:0,sample_size:20,independent_qa:false,outcome_verified:false})
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
const dollars=(c:any)=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',minimumFractionDigits:2}).format(Number(c||0)/100)
async function load(){try{state.value=await authed('/api/hivemind/economy');Object.assign(policy,state.value.policy||{},state.value.sharing||{});if(!improvement.project_id)improvement.project_id=state.value.projects?.[0]?.id||''}catch(e:any){message.value=e?.data?.message||e?.message}}
async function act(action:string,values:any){busy.value=action;message.value='';try{const result:any=await authed('/api/hivemind/action',{method:'POST',body:{action,...values}});message.value=action==='improvement'?`${result.decision.material?'Material':'Non-material'} · score ${result.decision.score}/100 · ${result.decision.mode.replaceAll('_',' ')}`:`${action.replaceAll('_',' ')} saved.`;await load()}catch(e:any){message.value=e?.data?.message||e?.message||'Action failed.'}finally{busy.value=''}}
onMounted(()=>{load();const timer=setInterval(load,15000);onUnmounted(()=>clearInterval(timer))})
</script>

<template><section class="hive-shell" aria-labelledby="hive-title"><header class="hive-hero"><div><div class="eyebrow">Shared capability economy</div><h1 id="hive-title">The Hivemind compounds what works.</h1><p>Every organization contributes privacy-safe operating patterns by default. Verified reuse earns credits; proprietary artifacts never leave their boundary.</p></div><div class="live-pill"><i/> Ledger refreshes every 15 seconds</div></header>
<div v-if="!state" class="loading">Loading contribution policies and verified outcomes…</div><template v-else>
  <div class="earnings-grid"><article v-for="item in [{l:'This hour',v:state.earnings.current_hour_cents},{l:'Today',v:state.earnings.today_cents},{l:'This month',v:state.earnings.month_cents},{l:'Available credits',v:state.earnings.available_credit_cents}]" :key="item.l"><span>{{item.l}}</span><strong>{{dollars(item.v)}}</strong></article></div>
  <div class="hive-grid"><article class="panel policy-panel"><div class="panel-head"><div><span class="kicker">Membership contract</span><h2>Share the pattern. Keep the IP.</h2></div><span class="required">Required by default</span></div><p class="muted">Madeus shares verified capability patterns, aggregate benchmarks, and outcome evidence. It structurally excludes source code, repositories, customer identities, raw datasets, credentials, secrets, private prompts, and contract text.</p><div class="boundary"><b>Network-safe contribution boundary</b><span v-for="x in state.sharing.shared_categories" :key="x">✓ {{x.replaceAll('_',' ')}}</span></div><form class="control-grid" @submit.prevent="act('policy',policy)"><label>Credit destination<select v-model="policy.rebate_mode"><option value="usage_rebate">Usage rebate</option><option value="subscription_credit">Subscription credit</option></select></label><label>Non-material updates<select v-model="policy.non_material_mode"><option value="auto_canary">Autonomous canary</option><option value="approval">Require approval</option><option value="off">Off</option></select></label><label>Material updates<select v-model="policy.material_mode"><option value="off">Off — recommended start</option><option value="approval">Require approval</option><option value="auto_canary">Autonomous canary</option></select></label><label>Materiality threshold <b>{{policy.materiality_threshold}}/100</b><input v-model.number="policy.materiality_threshold" type="range" min="1" max="100"></label><label>Maximum canary <b>{{policy.max_canary_percent}}%</b><input v-model.number="policy.max_canary_percent" type="range" min="1" max="25"></label><label class="check"><input v-model="policy.share_verified_improvements" type="checkbox"> Publish sanitized pattern after verified success</label><button :disabled="busy==='policy'">Save organization policy</button></form><p class="fine">Turning material autonomy on does not bypass QA, canary, rollback, approval authority, or the verified batch release train.</p></article>

  <article class="panel"><span class="kicker">Autonomous improvement immune system</span><h2>Propose an improvement</h2><p class="muted">Madeus scores materiality before execution. Non-material work can enter a bounded canary; material work starts off.</p><form class="stack" @submit.prevent="act('improvement',improvement)"><select v-model="improvement.project_id" required><option disabled value="">Choose workspace</option><option v-for="p in state.projects" :key="p.id" :value="p.id">{{p.name}}</option></select><input v-model="improvement.title" required maxlength="140" placeholder="Improve model-route cache efficiency"><textarea v-model="improvement.objective" required rows="3" placeholder="Outcome, constraint, and success measure"></textarea><div class="checks"><label><input v-model="improvement.customer_facing" type="checkbox"> Customer-facing</label><label><input v-model="improvement.data_or_permissions" type="checkbox"> Data or permissions</label><label><input v-model="improvement.hard_to_reverse" type="checkbox"> Hard to reverse</label></div><div class="two"><label>Affected users<input v-model.number="improvement.affected_users" type="number" min="0"></label><label>Revenue at risk ($)<input :value="improvement.revenue_at_risk_cents/100" type="number" min="0" @input="improvement.revenue_at_risk_cents=Number(($event.target as HTMLInputElement).value)*100"></label></div><button :disabled="busy==='improvement'">Score and route safely</button></form></article>

  <article class="panel"><span class="kicker">Contribution studio</span><h2>Publish reusable learning</h2><p class="muted">Describe the abstract pattern—not its implementation. It becomes discoverable only after independent QA and outcome verification.</p><form class="stack" @submit.prevent="act('contribute',contribution)"><input v-model="contribution.title" required placeholder="Capability title"><input v-model="contribution.problem_class" required placeholder="Problem class, e.g. model routing"><textarea v-model="contribution.pattern_summary" required rows="3" placeholder="Vendor-neutral pattern summary"></textarea><div class="two"><input v-model="contribution.metric" placeholder="Aggregate metric"><input v-model.number="contribution.improvement_percent" type="number" placeholder="Improvement %"></div><label>Aggregate sample size<input v-model.number="contribution.sample_size" type="number" min="0"></label><div class="checks"><label><input v-model="contribution.independent_qa" type="checkbox"> Independent QA passed</label><label><input v-model="contribution.outcome_verified" type="checkbox"> Outcome verified</label></div><button :disabled="busy==='contribute'">Publish safe manifest</button></form></article>

  <article class="panel market"><div class="panel-head"><div><span class="kicker">Cross-portfolio opportunity market</span><h2>Available verified patterns</h2></div><span>{{state.marketplace.length}} opportunities</span></div><div v-if="!state.marketplace.length" class="empty">The market is waiting for its first independently verified contribution.</div><div v-else class="market-list"><div v-for="item in state.marketplace" :key="item.id" class="market-card"><div><b>{{item.title}}</b><p>{{item.pattern_summary}}</p><small>{{item.problem_class}} · {{item.reuse_count}} verified reuses</small></div><button @click="act('adopt',{contribution_id:item.id})">Start bounded canary</button></div></div></article>
  </div>
  <div class="lower-grid"><article class="panel"><span class="kicker">Execution trail</span><h2>Recent improvement decisions</h2><div v-if="!state.runs.length" class="empty">No improvements proposed yet.</div><div v-for="run in state.runs" :key="run.id" class="row"><div><b>{{run.title}}</b><small>{{run.execution_policy.material?'Material':'Non-material'}} · score {{run.materiality_score}}/100</small></div><span :class="`status ${run.status}`">{{run.status.replaceAll('_',' ')}}</span></div></article><article class="panel"><span class="kicker">Auditable economics</span><h2>Credit ledger</h2><div v-if="!state.ledger.length" class="empty">Credits appear after another organization verifies incremental value.</div><div v-for="entry in state.ledger.slice(0,8)" :key="entry.id" class="row"><div><b>{{entry.event_type.replaceAll('_',' ')}}</b><small>{{new Date(entry.created_at).toLocaleString()}} · {{entry.credit_mode.replaceAll('_',' ')}}</small></div><strong>{{dollars(entry.amount_cents)}}</strong></div><p class="fine">Credits are accrued or available in this ledger; applying them to an invoice or usage balance is a separately audited settlement step.</p></article></div>
  <p v-if="message" class="notice" role="status">{{message}}</p>
</template></section></template>

<style scoped>
.hive-shell{min-height:100%;padding:28px;background:radial-gradient(circle at 80% 0,#e9fff7 0,transparent 28%),#f7f8f7;color:#101312}.hive-hero{max-width:1180px;margin:auto;display:flex;justify-content:space-between;gap:24px;align-items:end}.hive-hero h1{font-size:clamp(2rem,4vw,4rem);line-height:.96;letter-spacing:-.055em;max-width:720px}.hive-hero p{max-width:720px;margin-top:16px;color:#5f6662}.eyebrow,.kicker{font-size:10px;font-weight:800;letter-spacing:.15em;text-transform:uppercase;color:#087a55}.live-pill,.required{white-space:nowrap;border:1px solid #cfe5dc;border-radius:999px;padding:8px 11px;font-size:11px;background:#fff}.live-pill i{display:inline-block;width:7px;height:7px;border-radius:50%;background:#16a36d;margin-right:6px;box-shadow:0 0 0 5px #dff8ee}.loading,.empty{padding:28px;color:#737b77;font-size:13px}.earnings-grid,.hive-grid,.lower-grid{max-width:1180px;margin:22px auto 0;display:grid;gap:14px}.earnings-grid{grid-template-columns:repeat(4,1fr)}.earnings-grid article,.panel{background:rgba(255,255,255,.92);border:1px solid #e0e5e2;border-radius:18px;box-shadow:0 8px 28px rgba(16,37,27,.04)}.earnings-grid article{padding:18px}.earnings-grid span,.row small{display:block;color:#757d79;font-size:11px}.earnings-grid strong{display:block;margin-top:6px;font-size:24px;letter-spacing:-.04em}.hive-grid,.lower-grid{grid-template-columns:1fr 1fr}.panel{padding:22px}.policy-panel,.market{grid-column:1/-1}.panel h2{font-size:20px;margin-top:4px;letter-spacing:-.025em}.muted,.fine{color:#68706c;font-size:12px;margin-top:7px;line-height:1.55}.fine{font-size:10px}.panel-head{display:flex;justify-content:space-between;gap:16px}.boundary{display:flex;gap:10px;flex-wrap:wrap;margin:16px 0;padding:13px;background:#f3faf7;border-radius:12px;font-size:11px}.boundary b{width:100%}.control-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.stack{display:grid;gap:10px;margin-top:16px}.two,.checks{display:grid;grid-template-columns:1fr 1fr;gap:10px}.checks label,.check{display:flex;align-items:center;gap:7px;font-size:11px}.control-grid label,.stack label{font-size:11px;color:#4f5753}.control-grid select,.stack input,.stack select,.stack textarea{display:block;width:100%;margin-top:5px;border:1px solid #dce2de;border-radius:10px;padding:10px;background:#fff;font-size:12px}.control-grid input[type=range]{width:100%;margin-top:10px}.control-grid button,.stack button,.market-card button{border:0;border-radius:10px;background:#111513;color:white;padding:10px 14px;font-size:11px;font-weight:700}.market-list{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-top:15px}.market-card,.row{display:flex;align-items:center;justify-content:space-between;gap:14px;padding:13px;border:1px solid #e6e9e7;border-radius:12px}.market-card p{font-size:11px;color:#626a66;margin-top:4px}.market-card small{font-size:10px;color:#84908a}.row{margin-top:9px}.row b{font-size:12px}.status{padding:5px 8px;border-radius:999px;background:#eef1ef;font-size:10px}.status.queued,.status.verified{background:#e4f8ef;color:#087a55}.status.approval_required{background:#fff1d9;color:#925d00}.notice{position:sticky;bottom:16px;max-width:700px;margin:16px auto 0;padding:12px 16px;background:#101312;color:white;border-radius:12px;font-size:12px}@media(max-width:800px){.hive-shell{padding:20px 14px}.hive-hero{display:block}.live-pill{display:inline-block;margin-top:16px}.earnings-grid{grid-template-columns:1fr 1fr}.hive-grid,.lower-grid,.control-grid,.market-list{grid-template-columns:1fr}.policy-panel,.market{grid-column:auto}.panel-head{align-items:start}.required{white-space:normal}}
</style>
